// Mandray ny HTML avy amin'ny HTTP Request
const html = $input.first().json.body || 
             $input.first().json.data || 
             $input.first().json.content ||
             JSON.stringify($input.first().json);

const lettre = 'Z'; // ← ovay isaky ny lettre

const results = [];

// Mahita ny table.menuLink ihany
const tableMatch = html.match(/<table[^>]*class='menuLink'[^>]*>([\s\S]*?)<\/table>/);
if (!tableMatch) return [{ json: { error: "Table tsy hita" } }];

const tableHtml = tableMatch[1];

// Mahita rows tsirairay
const rowRegex = /<tr[^>]*>([\s\S]*?)<\/tr>/g;
let rowMatch;

while ((rowMatch = rowRegex.exec(tableHtml)) !== null) {
  const rowHtml = rowMatch[1];

  // Mandray ny td roa
  const tdRegex = /<td[^>]*>([\s\S]*?)<\/td>/g;
  const tds = [];
  let tdMatch;
  while ((tdMatch = tdRegex.exec(rowHtml)) !== null) {
    tds.push(tdMatch[1]);
  }

  if (tds.length < 2) continue;

  // Fototeny — link voalohany ao amin'ny td[0]
  const fotoMatch = tds[0].match(/href='\/bins\/teny2\/[^']*'>([^<]*(?:<[^>]*>[^<]*<\/[^>]*>)?[^<]*)<\/a>/);
  if (!fotoMatch) continue;

  const fototeny = fotoMatch[1]
    .replace(/<[^>]+>/g, '')   // esorina ny tags rehetra
    .replace(/&agrave;/g, 'à')
    .replace(/&eacute;/g, 'é')
    .replace(/&egrave;/g, 'è')
    .replace(/&ntilde;/g, 'ñ')
    .replace(/&ocirc;/g, 'ô')
    .trim();

  if (!fototeny || fototeny.length < 1) continue;

  // Sampateny — links rehetra ao amin'ny td[1]
  const sampRegex = /href='\/bins\/teny2\/[^']*'>([^<]*(?:<[^>]*>[^<]*<\/[^>]*>)?[^<]*)<\/a>/g;
  const sampateny = [];
  let sampMatch;

  while ((sampMatch = sampRegex.exec(tds[1])) !== null) {
    const teny = sampMatch[1]
      .replace(/<[^>]+>/g, '')
      .replace(/&agrave;/g, 'à')
      .replace(/&eacute;/g, 'é')
      .replace(/&egrave;/g, 'è')
      .replace(/&ntilde;/g, 'ñ')
      .replace(/&ocirc;/g, 'ô')
      .trim();
    if (teny) sampateny.push(teny);
  }

  results.push({
    json: {
      fototeny:  fototeny,
      sampateny: sampateny.join(', '),
      lettre:    lettre
    }
  });
}
return results.length > 0 ? results : [{ json: { error: "Tsy hita na inona na inona" } }];
